import{bV as n,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const _=JSON.parse('{"title":"自动角色分析","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/自动角色分析.md","filePath":"mumuainovel/自动角色分析.md","lastUpdated":1777605256000}'),t={name:"mumuainovel/自动角色分析.md"};function e(i,s,c,o,u,q){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="自动角色分析" tabindex="-1">自动角色分析 <a class="header-anchor" href="#自动角色分析" aria-label="Permalink to &quot;自动角色分析&quot;">​</a></h1><blockquote><p>模板键: <code>AUTO_CHARACTER_ANALYSIS</code> 分类: 自动角色引入 描述: 分析新生成的大纲，判断是否需要引入新角色 参数: [&quot;title&quot;, &quot;genre&quot;, &quot;theme&quot;, &quot;time_period&quot;, &quot;location&quot;, &quot;atmosphere&quot;, &quot;existing_characters&quot;, &quot;new_outlines&quot;, &quot;start_chapter&quot;, &quot;end_chapter&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是专业的小说角色设计顾问，擅长预测剧情发展对角色的需求。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【分析任务】</span></span>
<span class="line"><span>预测在接下来的{chapter_count}章续写中，根据剧情发展方向和阶段，是否需要引入新角色。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【重要说明】</span></span>
<span class="line"><span>这是预测性分析，而非基于已生成内容的事后分析。</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;project priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【项目信息】</span></span>
<span class="line"><span>书名：{title}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【世界观】</span></span>
<span class="line"><span>时间背景：{time_period}</span></span>
<span class="line"><span>地理位置：{location}</span></span>
<span class="line"><span>氛围基调：{atmosphere}</span></span>
<span class="line"><span>&lt;/project&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;context priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【已有角色】</span></span>
<span class="line"><span>{existing_characters}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【已有章节概览】</span></span>
<span class="line"><span>{all_chapters_brief}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【续写计划】</span></span>
<span class="line"><span>- 起始章节：第{start_chapter}章</span></span>
<span class="line"><span>- 续写数量：{chapter_count}章</span></span>
<span class="line"><span>- 剧情阶段：{plot_stage}</span></span>
<span class="line"><span>- 发展方向：{story_direction}</span></span>
<span class="line"><span>&lt;/context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;analysis_framework priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【预测分析维度】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**1. 剧情需求预测**</span></span>
<span class="line"><span>根据发展方向，哪些场景、冲突需要新角色参与？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**2. 角色充分性**</span></span>
<span class="line"><span>现有角色是否足以支撑即将发生的剧情？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**3. 引入时机**</span></span>
<span class="line"><span>新角色应该在哪个章节登场最合适？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**4. 重要性判断**</span></span>
<span class="line"><span>新角色对后续剧情的影响程度如何？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**5. 角色冲突缺口**</span></span>
<span class="line"><span>现有角色的目标（goal）和外部冲突（external_conflict）中，是否有缺失的对手、盟友或变数者？</span></span>
<span class="line"><span>如果某个角色缺少有效的对立面，建议引入对应角色。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【预测依据】</span></span>
<span class="line"><span>- 剧情阶段的典型角色需求（如：高潮阶段可能需要强力对手）</span></span>
<span class="line"><span>- 故事发展方向的逻辑需要（如：进入新地点需要当地角色）</span></span>
<span class="line"><span>- 冲突升级的角色需求（如：更强的反派、意外的盟友）</span></span>
<span class="line"><span>- 世界观扩展的需要（如：新组织、新势力的代表）</span></span>
<span class="line"><span>- 现有角色冲突网络缺口（如：某角色有目标但无对手）</span></span>
<span class="line"><span>&lt;/analysis_framework&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>返回纯JSON对象（两种情况之一）：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**情况A：需要新角色**</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;needs_new_characters&quot;: true,</span></span>
<span class="line"><span>  &quot;reason&quot;: &quot;预测分析原因（150-200字），说明为什么即将的剧情需要新角色&quot;,</span></span>
<span class="line"><span>  &quot;character_count&quot;: 2,</span></span>
<span class="line"><span>  &quot;character_specifications&quot;: [</span></span>
<span class="line"><span>    {{</span></span>
<span class="line"><span>      &quot;name&quot;: &quot;建议的角色名字（可选）&quot;,</span></span>
<span class="line"><span>      &quot;role_description&quot;: &quot;角色在剧情中的定位和作用（100-150字）&quot;,</span></span>
<span class="line"><span>      &quot;suggested_role_type&quot;: &quot;supporting/antagonist/protagonist&quot;,</span></span>
<span class="line"><span>      &quot;importance&quot;: &quot;high/medium/low&quot;,</span></span>
<span class="line"><span>      &quot;appearance_chapter&quot;: {start_chapter},</span></span>
<span class="line"><span>      &quot;goal&quot;: &quot;该角色的核心目标（一句话）&quot;,</span></span>
<span class="line"><span>      &quot;conflict_target&quot;: &quot;该角色与哪个现有角色形成什么冲突&quot;,</span></span>
<span class="line"><span>      &quot;key_abilities&quot;: [&quot;能力1&quot;, &quot;能力2&quot;],</span></span>
<span class="line"><span>      &quot;plot_function&quot;: &quot;在剧情中的具体功能&quot;,</span></span>
<span class="line"><span>      &quot;relationship_suggestions&quot;: [</span></span>
<span class="line"><span>        {{</span></span>
<span class="line"><span>          &quot;target_character&quot;: &quot;现有角色名&quot;,</span></span>
<span class="line"><span>          &quot;relationship_type&quot;: &quot;建议的关系类型&quot;,</span></span>
<span class="line"><span>          &quot;reason&quot;: &quot;为什么建立这种关系&quot;</span></span>
<span class="line"><span>        }}</span></span>
<span class="line"><span>      ]</span></span>
<span class="line"><span>    }}</span></span>
<span class="line"><span>  ]</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>**情况B：不需要新角色**</span></span>
<span class="line"><span>{{</span></span>
<span class="line"><span>  &quot;needs_new_characters&quot;: false,</span></span>
<span class="line"><span>  &quot;reason&quot;: &quot;现有角色足以支撑即将的剧情发展，说明理由&quot;</span></span>
<span class="line"><span>}}</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 这是预测性分析，面向未来剧情</span></span>
<span class="line"><span>✅ 考虑剧情的自然发展和节奏</span></span>
<span class="line"><span>✅ 确保引入必要性，不为引入而引入</span></span>
<span class="line"><span>✅ 优先考虑角色的长期作用</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【关系建议要求】</span></span>
<span class="line"><span>✅ relationship_suggestions优先建议社交、职业、立场类关系</span></span>
<span class="line"><span>✅ 血缘关系建议最多1条，且须有充分理由</span></span>
<span class="line"><span>✅ 关系建议应服务于冲突网络的完善</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 输出markdown标记</span></span>
<span class="line"><span>❌ 基于已生成内容做事后分析</span></span>
<span class="line"><span>❌ 为了引入角色而强行引入</span></span>
<span class="line"><span>❌ 设计一次性功能角色</span></span>
<span class="line"><span>❌ 血缘关系建议超过1条</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const g=n(t,[["render",e]]);export{_ as __pageData,g as default};
